    // ==================== Bug F9: PPTX lineDash invalid values silent fallback to Solid ====================

    [Fact]
    public void BugF9_Pptx_SetLineDash_InvalidValue_ShouldThrowArgumentException()
    {
        // BUG: lineDash switch has `_ => Solid` fallback at PowerPointHandler.ShapeProperties.cs:336
        using var handler = new PowerPointHandler(_pptxPath, editable: true);
        var act = () => handler.Set("/slide[1]/shape[1]", new() { ["linedash"] = "invalid" });
