    // ==================== Bug F10: XLSX alignment.horizontal invalid values silent null ====================

    [Fact]
    public void BugF10_Xlsx_SetAlignmentHorizontal_InvalidValue_ShouldThrowArgumentException()
    {
        // BUG: ParseHAlign returns null for unknown values (ExcelStyleManager.cs:764)
        // null is set on alignment.Horizontal — silently no-op
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["alignment.horizontal"] = "invalid" });
        act.Should().Throw<ArgumentException>("'invalid' horizontal alignment should be rejected");
    }

    [Fact]
    public void BugF10_Xlsx_SetAlignmentHorizontal_EmptyValue_ShouldThrowArgumentException()
    {
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["alignment.horizontal"] = "" });
        act.Should().Throw<ArgumentException>("empty horizontal alignment should be rejected");
    }

    // ==================== Bug F11: XLSX font.size NaN/Infinity silent acceptance ====================

    [Fact]
    public void BugF11_Xlsx_SetFontSize_NaN_ShouldThrowArgumentException()
    {
        // BUG: ExcelStyleManager.cs:297 — double.TryParse("NaN") succeeds, NaN used as font size
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["font.size"] = "NaN" });
        act.Should().Throw<ArgumentException>("NaN font.size should be rejected");
    }

    [Fact]
    public void BugF11_Xlsx_SetFontSize_Infinity_ShouldThrowArgumentException()
    {
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["font.size"] = "Infinity" });
        act.Should().Throw<ArgumentException>("Infinity font.size should be rejected");
    }

    [Fact]
    public void BugF11_Xlsx_SetFontSize_InvalidString_ShouldThrowArgumentException()
    {
        // BUG: ExcelStyleManager.cs:297 — TryParse failure silently uses base font size (no error)
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["font.size"] = "abc" });
        act.Should().Throw<ArgumentException>("invalid font.size string should be rejected, not silently ignored");
    }

    // ==================== Bug F4 extension: DOCX Add also has alignment silent fallback ====================

    [Fact]
    public void BugF4b_Docx_AddParagraph_InvalidAlignment_ShouldThrowArgumentException()
    {
        // BUG: WordHandler.Add.cs:63 — same `_ => JustificationValues.Left` pattern as Set
        using var handler = new WordHandler(_docxPath, editable: true);
        var act = () => handler.Add("/body", "paragraph", null,
            new() { ["text"] = "Hello", ["alignment"] = "invalid" });
        act.Should().Throw<ArgumentException>("invalid alignment in Add should be rejected");
    }

