    // ==================== Bug F5: XLSX border.all invalid values silent failure ====================

    [Fact]
    public void BugF5_Xlsx_SetBorderAll_InvalidValue_ShouldThrowArgumentException()
    {
        // BUG: border.all="invalid" silently ignored — no exception, no effect
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["border.all"] = "invalid" });
        act.Should().Throw<ArgumentException>("'invalid' is not a valid border style and should be rejected");
    }

    [Fact]
    public void BugF5_Xlsx_SetBorderAll_EmptyValue_ShouldThrowArgumentException()
    {
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["border.all"] = "" });
        act.Should().Throw<ArgumentException>("empty border style should be rejected");
    }

    [Fact]
    public void BugF5_Xlsx_SetBorderAll_SolidNotValid_ShouldThrowArgumentException()
    {
        // 'solid' is a CSS border style, not a valid Excel border style (valid: thin, medium, thick, etc.)
        using var handler = new ExcelHandler(_xlsxPath, editable: true);
        handler.Add("/Sheet1", "cell", null, new() { ["ref"] = "A1", ["value"] = "test" });
        var act = () => handler.Set("/Sheet1/A1", new() { ["border.all"] = "solid" });
        act.Should().Throw<ArgumentException>("'solid' is not a valid Excel border style");
    }
